import pandas as pd

# Load the data
last_year_history = var_functions.query_db_18

# Create DataFrame
df = pd.DataFrame(last_year_history)

# Parse dates
df['createddate_parsed'] = pd.to_datetime(df['createddate'])

# Track transfers per agent
transfers_per_agent = {}
cases_per_agent = {}

# Iterate through records
for _, row in df.iterrows():
    old_agent = row['oldvalue__c']
    new_agent = row['newvalue__c']

    # Count cases handled by each agent
    if new_agent != 'None':
        cases_per_agent[new_agent] = cases_per_agent.get(new_agent, 0) + 1

    # Count transfers FROM each agent
    if old_agent != 'None' and old_agent != 'None':
        transfers_per_agent[old_agent] = transfers_per_agent.get(old_agent, 0) + 1

# Filter agents with more than 0 cases
eligible_agents = {}
for agent, case_count in cases_per_agent.items():
    if case_count > 0:
        eligible_agents[agent] = {
            'case_count': case_count,
            'transfer_count': transfers_per_agent.get(agent, 0)
        }

print(f"Eligible agents: {len(eligible_agents)}")

# Find agent with minimum transfers among eligible
min_transfers = float('inf')
agent_with_min = None

for agent, stats in eligible_agents.items():
    if stats['transfer_count'] < min_transfers:
        min_transfers = stats['transfer_count']
        agent_with_min = agent

print(f"Agent with minimum transfers: {agent_with_min}")
print(f"Transfer count: {min_transfers}")

result = agent_with_min if agent_with_min else "None found"

