import json
import os

# Try to find the data file
data_file = None
for key, value in locals().items():
    if 'query_db' in key and isinstance(value, str) and '.json' in value:
        data_file = value
        break

if data_file and os.path.exists(data_file):
    with open(data_file, 'r') as f:
        data = json.load(f)
else:
    print("Could not find data file")
    data = []

transfer_counts = {}
case_counts = {}

for record in data:
    old_agent = record['oldvalue__c']
    new_agent = record['newvalue__c']

    if new_agent != 'None':
        case_counts[new_agent] = case_counts.get(new_agent, 0) + 1

    if old_agent != 'None':
        transfer_counts[old_agent] = transfer_counts.get(old_agent, 0) + 1

eligible = [(agent, transfer_counts.get(agent, 0)) for agent in case_counts if case_counts[agent] > 0]

if eligible:
    eligible.sort(key=lambda x: (x[1], x[0]))
    result = eligible[0][0]
else:
    result = None

print("__RESULT__:")
print(json.dumps(result))

